          { question: 'What is the "black box" problem in AI?', options: ['AI systems that only work in dark environments', 'AI systems whose internal reasoning is opaque', 'AI systems that refuse to answer questions', 'AI systems that use encrypted data'], answer: 1 },
          { question: 'What does the EU AI Act use to categorize AI systems?', options: ['Cost', 'Speed', 'Risk level', 'Country of origin'], answer: 2 }
