          { question: 'In the avalanche debt repayment method, which debt do you pay first?', options: ['The smallest balance', 'The newest debt', 'The highest-interest debt', 'The oldest debt'], answer: 2 },
          { question: 'What is a secured credit card?', options: ['A card with no credit limit', 'A card where you deposit money as collateral', 'A card only for business use', 'A card with zero interest'], answer: 1 }
