          { question: 'What did Google\'s Project Aristotle identify as the most important factor in team performance?', options: ['Individual expertise', 'Team size', 'Psychological safety', 'Clear goals'], answer: 2 },
          { question: 'What is transformational leadership?', options: ['Changing the company structure', 'Inspiring by connecting work to meaningful larger purpose', 'Managing through strict rules', 'Leading through financial incentives only'], answer: 1 },
          { question: 'What is confirmation bias?', options: ['Seeking information that confirms existing beliefs', 'Being overly confident in decisions', 'Preferring the first option presented', 'Following the group consensus'], answer: 0 },
          { question: 'What does Simon Sinek\'s "Start With Why" framework suggest?', options: ['Begin presentations with your credentials', 'Communicate purpose before describing what you do or how you do it', 'Always question every decision', 'Start meetings by asking why they are needed'], answer: 1 }
